import{_ as s,o as i,c as n,ae as e}from"./chunks/framework.z1tb74tW.js";const u=JSON.parse('{"title":"Project Structure","description":"","frontmatter":{},"headers":[],"relativePath":"guide/project-structure.md","filePath":"guide/project-structure.md"}'),t={name:"guide/project-structure.md"};function p(l,a,o,r,c,d){return i(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="project-structure" tabindex="-1">Project Structure <a class="header-anchor" href="#project-structure" aria-label="Permalink to &quot;Project Structure&quot;">​</a></h1><p>Understanding the standard NanoBoot project structure helps you navigate and organize your application effectively.</p><h2 id="standard-directory-layout" tabindex="-1">Standard Directory Layout <a class="header-anchor" href="#standard-directory-layout" aria-label="Permalink to &quot;Standard Directory Layout&quot;">​</a></h2><p>A typical NanoBoot application follows this directory structure:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my-app/</span></span>
<span class="line"><span>├── pom.xml                 # Maven configuration and dependencies</span></span>
<span class="line"><span>├── .gitignore              # Git ignore patterns</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── main/</span></span>
<span class="line"><span>│   │   ├── java/</span></span>
<span class="line"><span>│   │   │   └── com/</span></span>
<span class="line"><span>│   │   │       └── example/</span></span>
<span class="line"><span>│   │   │           ├── MyAppApplication.java    # Main application entry point</span></span>
<span class="line"><span>│   │   │           ├── controller/              # Web controllers</span></span>
<span class="line"><span>│   │   │           │   └── ApplicationController.java</span></span>
<span class="line"><span>│   │   │           ├── service/                 # Business logic services</span></span>
<span class="line"><span>│   │   │           │   └── ApplicationService.java</span></span>
<span class="line"><span>│   │   │           ├── repository/              # Data access layer (optional)</span></span>
<span class="line"><span>│   │   │           │   └── UserRepository.java</span></span>
<span class="line"><span>│   │   │           └── dto/                     # Data Transfer Objects</span></span>
<span class="line"><span>│   │   │               └── UserDto.java</span></span>
<span class="line"><span>│   │   └── resources/                           # Configuration files</span></span>
<span class="line"><span>│   │       ├── application.properties           # Main configuration</span></span>
<span class="line"><span>│   │       └── templates/                       # Template files (if needed)</span></span>
<span class="line"><span>│   └── test/                                    # Unit and integration tests</span></span>
<span class="line"><span>│       └── java/</span></span>
<span class="line"><span>│           └── com/</span></span>
<span class="line"><span>│               └── example/</span></span>
<span class="line"><span>│                   └── MyAppApplicationTests.java</span></span>
<span class="line"><span>└── target/                 # Build output directory (generated during build)</span></span></code></pre></div><h2 id="key-files-and-directories" tabindex="-1">Key Files and Directories <a class="header-anchor" href="#key-files-and-directories" aria-label="Permalink to &quot;Key Files and Directories&quot;">​</a></h2><h3 id="pom-xml" tabindex="-1">pom.xml <a class="header-anchor" href="#pom-xml" aria-label="Permalink to &quot;pom.xml&quot;">​</a></h3><p>This is your Maven configuration file that manages:</p><ul><li>Project coordinates (groupId, artifactId, version)</li><li>Dependencies on NanoBoot modules</li><li>Build plugins and configurations</li><li>Java compiler settings</li></ul><h3 id="main-application-class" tabindex="-1">Main Application Class <a class="header-anchor" href="#main-application-class" aria-label="Permalink to &quot;Main Application Class&quot;">​</a></h3><p>Located at <code>src/main/java/com/example/MyAppApplication.java</code>, this is the entry point:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NanoBootApplication</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyAppApplication</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> static</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> main</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">String</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[] </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">args</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        NanoBootApplicationRunner.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(MyAppApplication.class, args);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="application-properties" tabindex="-1">Application Properties <a class="header-anchor" href="#application-properties" aria-label="Permalink to &quot;Application Properties&quot;">​</a></h3><p>The <code>src/main/resources/application.properties</code> file contains configuration:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Application Properties</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">app.name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=my-app</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server.port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=8080</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Database Configuration (examples)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># spring.datasource.url=jdbc:h2:mem:testdb</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># spring.datasource.driver-class-name=org.h2.Driver</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># spring.datasource.username=sa</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># spring.datasource.password=</span></span></code></pre></div><h3 id="package-organization" tabindex="-1">Package Organization <a class="header-anchor" href="#package-organization" aria-label="Permalink to &quot;Package Organization&quot;">​</a></h3><p>The recommended package structure separates concerns:</p><ul><li><strong>controllers</strong>: Handle HTTP requests and responses</li><li><strong>services</strong>: Contain business logic</li><li><strong>repositories</strong>: Handle data persistence (when using data module)</li><li><strong>dto</strong>: Data Transfer Objects for API contracts</li><li><strong>config</strong>: Configuration classes (when needed)</li></ul><h2 id="module-specific-structures" tabindex="-1">Module-Specific Structures <a class="header-anchor" href="#module-specific-structures" aria-label="Permalink to &quot;Module-Specific Structures&quot;">​</a></h2><p>Depending on which NanoBoot modules you use, you might have additional directories:</p><h3 id="data-module" tabindex="-1">Data Module <a class="header-anchor" href="#data-module" aria-label="Permalink to &quot;Data Module&quot;">​</a></h3><p>If using <code>nano-boot-data</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/main/java/com/example/</span></span>
<span class="line"><span>├── config/</span></span>
<span class="line"><span>│   └── DatabaseConfig.java</span></span>
<span class="line"><span>├── repository/</span></span>
<span class="line"><span>│   ├── UserRepository.java</span></span>
<span class="line"><span>│   └── ProductRepository.java</span></span>
<span class="line"><span>└── entity/</span></span>
<span class="line"><span>    ├── User.java</span></span>
<span class="line"><span>    └── Product.java</span></span></code></pre></div><h3 id="websocket-module" tabindex="-1">WebSocket Module <a class="header-anchor" href="#websocket-module" aria-label="Permalink to &quot;WebSocket Module&quot;">​</a></h3><p>If using <code>nano-boot-websocket</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/main/java/com/example/</span></span>
<span class="line"><span>└── websocket/</span></span>
<span class="line"><span>    ├── ChatEndpoint.java</span></span>
<span class="line"><span>    └── MessageHandler.java</span></span></code></pre></div><h2 id="configuration-files" tabindex="-1">Configuration Files <a class="header-anchor" href="#configuration-files" aria-label="Permalink to &quot;Configuration Files&quot;">​</a></h2><h3 id="application-properties-1" tabindex="-1">application.properties <a class="header-anchor" href="#application-properties-1" aria-label="Permalink to &quot;application.properties&quot;">​</a></h3><p>Primary configuration file for:</p><ul><li>Server settings (port, context path)</li><li>Database connections</li><li>Custom application properties</li><li>Third-party service configurations</li></ul><h3 id="gitignore" tabindex="-1">.gitignore <a class="header-anchor" href="#gitignore" aria-label="Permalink to &quot;.gitignore&quot;">​</a></h3><p>Standard ignores for:</p><ul><li>Build artifacts (<code>target/</code>)</li><li>IDE files</li><li>Log files</li><li>Temporary files</li><li>Secrets and configuration files</li></ul><h2 id="testing-structure" tabindex="-1">Testing Structure <a class="header-anchor" href="#testing-structure" aria-label="Permalink to &quot;Testing Structure&quot;">​</a></h2><p>Unit and integration tests follow the same package structure as the main code:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Test</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> testUserService</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // Test code here</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><h3 id="package-naming" tabindex="-1">Package Naming <a class="header-anchor" href="#package-naming" aria-label="Permalink to &quot;Package Naming&quot;">​</a></h3><p>Use reverse domain name notation:</p><ul><li><code>com.company.project</code> - For company projects</li><li><code>org.projectname</code> - For open source projects</li></ul><h3 id="layer-separation" tabindex="-1">Layer Separation <a class="header-anchor" href="#layer-separation" aria-label="Permalink to &quot;Layer Separation&quot;">​</a></h3><p>Maintain clear separation between layers:</p><ul><li>Controllers should only handle HTTP concerns</li><li>Services should contain business logic</li><li>Repositories should handle data persistence</li></ul><h3 id="configuration-management" tabindex="-1">Configuration Management <a class="header-anchor" href="#configuration-management" aria-label="Permalink to &quot;Configuration Management&quot;">​</a></h3><p>Store configuration in <code>application.properties</code>:</p><ul><li>Use meaningful property names</li><li>Provide default values with <code>\${property:defaultValue}</code></li><li>Separate environment-specific configs when needed</li></ul><h3 id="resource-organization" tabindex="-1">Resource Organization <a class="header-anchor" href="#resource-organization" aria-label="Permalink to &quot;Resource Organization&quot;">​</a></h3><p>Keep resources organized:</p><ul><li>Static assets in appropriate directories</li><li>Templates in <code>src/main/resources/templates</code></li><li>Properties files in <code>src/main/resources</code></li></ul><p>This structure provides a solid foundation for organizing your NanoBoot applications and scales well as your project grows.</p>`,50)])])}const g=s(t,[["render",p]]);export{u as __pageData,g as default};
